kham khảo code này nó lấy thông tin được nè 
<!doctype html>
<html lang="en">
  <head>
    <meta charset="UTF-8">
    <link rel="stylesheet" href="//gisvietnam.ddns.net:8080/geoserver/openlayers3/ol.css" type="text/css">
    <style>
        .ol-zoom {
          top: 52px;
        }
        .ol-toggle-options {
          z-index: 1000;
          background: rgba(255,255,255,0.4);
          border-radius: 4px;
          padding: 2px;
          position: absolute;
          left: 8px;
          top: 8px;
        }
        #updateFilterButton, #resetFilterButton {
          height: 22px;
          width: 22px;
          text-align: center;
          text-decoration: none !important;
          line-height: 22px;
          margin: 1px;
          font-family: 'Lucida Grande',Verdana,Geneva,Lucida,Arial,Helvetica,sans-serif;
          font-weight: bold !important;
          background: rgba(0,60,136,0.5);
          color: white !important;
          padding: 2px;
        }
        .ol-toggle-options a {
          background: rgba(0,60,136,0.5);
          color: white;
          display: block;
          font-family: 'Lucida Grande',Verdana,Geneva,Lucida,Arial,Helvetica,sans-serif;
          font-size: 19px;
          font-weight: bold;
          height: 22px;
          line-height: 11px;
          margin: 1px;
          padding: 0;
          text-align: center;
          text-decoration: none;
          width: 22px;
          border-radius: 2px;
        }
        .ol-toggle-options a:hover {
          color: #fff;
          text-decoration: none;
          background: rgba(0,60,136,0.7);
        }
        body {
            font-family: Verdana, Geneva, Arial, Helvetica, sans-serif;
            font-size: small;
        }
        iframe {
            width: 100%;
            height: 250px;
            border: none;
        }
        /* Toolbar styles */
        #toolbar {
            position: relative;
            padding-bottom: 0.5em;
        }
        #toolbar ul {
            list-style: none;
            padding: 0;
            margin: 0;
        }
        #toolbar ul li {
            float: left;
            padding-right: 1em;
            padding-bottom: 0.5em;
        }
        #toolbar ul li a {
            font-weight: bold;
            font-size: smaller;
            vertical-align: middle;
            color: black;
            text-decoration: none;
        }
        #toolbar ul li a:hover {
            text-decoration: underline;
        }
        #toolbar ul li * {
            vertical-align: middle;
        }
        #map {
            clear: both;
            position: relative;
            width: 679px;
            height: 768px;
            border: 1px solid black;
        }
        #wrapper {
            width: 679px;
        }
        #location {
            float: right;
        }
        /* Styles used by the default GetFeatureInfo output, added to make IE happy */
        table.featureInfo, table.featureInfo td, table.featureInfo th {
            border: 1px solid #ddd;
            border-collapse: collapse;
            margin: 0;
            padding: 0;
            font-size: 90%;
            padding: .2em .1em;
        }
        table.featureInfo th {
            padding: .2em .2em;
            font-weight: bold;
            background: #eee;
        }
        table.featureInfo td {
            background: #fff;
        }
        table.featureInfo tr.odd td {
            background: #eee;
        }
        table.featureInfo caption {
            text-align: left;
            font-size: 100%;
            font-weight: bold;
            padding: .2em .2em;
        }
    </style>
    <script src="//gisvietnam.ddns.net:8080/geoserver/openlayers3/ol.js" type="text/javascript"></script>
    <title>OpenLayers map preview</title>
  </head>
  <body>
    <div id="toolbar" style="display: none;">
      <ul>
        <li>
          <a>WMS version:</a>
          <select id="wmsVersionSelector" onchange="setWMSVersion(value)">
            <option value="1.1.1">1.1.1</option>
            <option value="1.3.0">1.3.0</option>
          </select>
        </li>
        <li>
          <a>Tiling:</a>
          <select id="tilingModeSelector" onchange="setTileMode(value)">
            <option value="untiled">Single tile</option>
            <option value="tiled">Tiled</option>
          </select>
        </li>
        <li>
          <a>Antialias:</a>
          <select id="antialiasSelector" onchange="setAntialiasMode(value)">
            <option value="full">Full</option>
            <option value="text">Text only</option>
            <option value="none">Disabled</option>
          </select>
        </li>
        <li>
          <a>Format:</a>
          <select id="imageFormatSelector" onchange="setImageFormat(value)">
            <option value="image/png">PNG 24bit</option>
            <option value="image/png8">PNG 8bit</option>
            <option value="image/gif">GIF</option>
            <option id="jpeg" value="image/jpeg">JPEG</option>
            <option id="jpeg-png" value="image/vnd.jpeg-png">JPEG-PNG</option>
            <option id="jpeg-png8" value="image/vnd.jpeg-png8">JPEG-PNG8</option>
          </select>
        </li>
        <li>
          <a>Styles:</a>
          <select id="imageFormatSelector" onchange="setStyle(value)">
            <option value="">Default</option>
          </select>
        </li>
        <li>
          <a>Width/Height:</a>
          <select id="widthSelector" onchange="setWidth(value)">
             <!--
             These values come from a statistics of the viewable area given a certain screen area
             (but have been adapted a litte, simplified numbers, added some resolutions for wide screen)
             You can find them here: http://www.evolt.org/article/Real_World_Browser_Size_Stats_Part_II/20/2297/
             --><option value="auto">Auto</option>
                <option value="600">600</option>
                <option value="750">750</option>
                <option value="950">950</option>
                <option value="1000">1000</option>
                <option value="1200">1200</option>
                <option value="1400">1400</option>
                <option value="1600">1600</option>
                <option value="1900">1900</option>
            </select>
            <select id="heigthSelector" onchange="setHeight(value)">
                <option value="auto">Auto</option>
                <option value="300">300</option>
                <option value="400">400</option>
                <option value="500">500</option>
                <option value="600">600</option>
                <option value="700">700</option>
                <option value="800">800</option>
                <option value="900">900</option>
                <option value="1000">1000</option>
            </select>
          </li>
          <li>
              <a>Filter:</a>
              <select id="filterType">
                  <option value="cql">CQL</option>
                  <option value="ogc">OGC</option>
                  <option value="fid">FeatureID</option>
              </select>
              <input type="text" size="80" id="filter"/>
              <a id="updateFilterButton" href="#" onClick="updateFilter()" title="Apply filter">Apply</a>
              <a id="resetFilterButton" href="#" onClick="resetFilter()" title="Reset filter">Reset</a>
          </li>
        </ul>
      </div>
    <div id="map">
      <div class="ol-toggle-options ol-unselectable"><a title="Toggle options toolbar" onClick="toggleControlPanel()" href="#toggle">...</a></div>
    </div>
    <div id="wrapper">
        <div id="location"></div>
        <div id="scale">
    </div>
    <div id="nodelist">
        <em>Click on the map to get feature info</em>
    </div>
    <script type="text/javascript">
      var pureCoverage = false;
      // if this is just a coverage or a group of them, disable a few items,
      // and default to jpeg format
      var format = 'image/png';
      var bounds = [588682.6875, 1240005.75,
                    601832.875, 1254864.125];
      if (pureCoverage) {
        document.getElementById('antialiasSelector').disabled = true;
        document.getElementById('jpeg').selected = true;
        format = "image/jpeg";
      }

      var supportsFiltering = true;
      if (!supportsFiltering) {
        document.getElementById('filterType').disabled = true;
        document.getElementById('filter').disabled = true;
        document.getElementById('updateFilterButton').disabled = true;
        document.getElementById('resetFilterButton').disabled = true;
      }

      var mousePositionControl = new ol.control.MousePosition({
        className: 'custom-mouse-position',
        target: document.getElementById('location'),
        coordinateFormat: ol.coordinate.createStringXY(5),
        undefinedHTML: '&nbsp;'
      });
      var untiled = new ol.layer.Image({
        source: new ol.source.ImageWMS({
          ratio: 1,
          url: 'http://gisvietnam.ddns.net:8080/geoserver/hochiminh_binhduong/wms',
          params: {'FORMAT': format,
                   'VERSION': '1.1.1',  
                "STYLES": '',
                "LAYERS": 'hochiminh_binhduong:baubang',
                "exceptions": 'application/vnd.ogc.se_inimage',
          }
        })
      });
      var tiled = new ol.layer.Tile({
        visible: false,
        source: new ol.source.TileWMS({
          url: 'http://gisvietnam.ddns.net:8080/geoserver/hochiminh_binhduong/wms',
          params: {'FORMAT': format, 
                   'VERSION': '1.1.1',
                   tiled: true,
                "STYLES": '',
                "LAYERS": 'hochiminh_binhduong:baubang',
                "exceptions": 'application/vnd.ogc.se_inimage',
             tilesOrigin: 588682.6875 + "," + 1240005.75
          }
        })
      });
      var projection = new ol.proj.Projection({
          code: 'EPSG:9210',
          units: 'm',
          global: false
      });
      var map = new ol.Map({
        controls: ol.control.defaults({
          attribution: false
        }).extend([mousePositionControl]),
        target: 'map',
        layers: [
          untiled,
          tiled
        ],
        view: new ol.View({
           projection: projection
        })
      });
      map.getView().on('change:resolution', function(evt) {
        var resolution = evt.target.get('resolution');
        var units = map.getView().getProjection().getUnits();
        var dpi = 25.4 / 0.28;
        var mpu = ol.proj.METERS_PER_UNIT[units];
        var scale = resolution * mpu * 39.37 * dpi;
        if (scale >= 9500 && scale <= 950000) {
          scale = Math.round(scale / 1000) + "K";
        } else if (scale >= 950000) {
          scale = Math.round(scale / 1000000) + "M";
        } else {
          scale = Math.round(scale);
        }
        document.getElementById('scale').innerHTML = "Scale = 1 : " + scale;
      });
      map.getView().fit(bounds, map.getSize());
      map.on('singleclick', function(evt) {
        document.getElementById('nodelist').innerHTML = "Loading... please wait...";
        var view = map.getView();
        var viewResolution = view.getResolution();
        var source = untiled.get('visible') ? untiled.getSource() : tiled.getSource();
        var url = source.getGetFeatureInfoUrl(
          evt.coordinate, viewResolution, view.getProjection(),
          {'INFO_FORMAT': 'text/html', 'FEATURE_COUNT': 50});
        if (url) {
          document.getElementById('nodelist').innerHTML = '<iframe seamless src="' + url + '"></iframe>';
        }
      });

      // sets the chosen WMS version
      function setWMSVersion(wmsVersion) {
        map.getLayers().forEach(function(lyr) {
          lyr.getSource().updateParams({'VERSION': wmsVersion});
        });
        if(wmsVersion == "1.3.0") {
            origin = bounds[1] + ',' + bounds[0];
        } else {
            origin = bounds[0] + ',' + bounds[1];
        }
        tiled.getSource().updateParams({'tilesOrigin': origin});
      }

      // Tiling mode, can be 'tiled' or 'untiled'
      function setTileMode(tilingMode) {
        if (tilingMode == 'tiled') {
          untiled.set('visible', false);
          tiled.set('visible', true);
        } else {
          tiled.set('visible', false);
          untiled.set('visible', true);
        }
      }

      function setAntialiasMode(mode) {
        map.getLayers().forEach(function(lyr) {
          lyr.getSource().updateParams({'FORMAT_OPTIONS': 'antialias:' + mode});
        });
      }

      // changes the current tile format
      function setImageFormat(mime) {
        map.getLayers().forEach(function(lyr) {
          lyr.getSource().updateParams({'FORMAT': mime});
        });
      }

      function setStyle(style){
        map.getLayers().forEach(function(lyr) {
          lyr.getSource().updateParams({'STYLES': style});
        });
      }

      function setWidth(size){
        var mapDiv = document.getElementById('map');
        var wrapper = document.getElementById('wrapper');

        if (size == "auto") {
          // reset back to the default value
          mapDiv.style.width = null;
          wrapper.style.width = null;
        }
        else {
          mapDiv.style.width = size + "px";
          wrapper.style.width = size + "px";
        }
        // notify OL that we changed the size of the map div
        map.updateSize();
      }

      function setHeight(size){
        var mapDiv = document.getElementById('map');
        if (size == "auto") {
          // reset back to the default value
          mapDiv.style.height = null;
        }
        else {
          mapDiv.style.height = size + "px";
        }
        // notify OL that we changed the size of the map div
        map.updateSize();
      }

      function updateFilter(){
        if (!supportsFiltering) {
          return;
        }
        var filterType = document.getElementById('filterType').value;
        var filter = document.getElementById('filter').value;
        // by default, reset all filters
        var filterParams = {
          'FILTER': null,
          'CQL_FILTER': null,
          'FEATUREID': null
        };
        if (filter.replace(/^\s\s*/, '').replace(/\s\s*$/, '') != "") {
          if (filterType == "cql") {
            filterParams["CQL_FILTER"] = filter;
          }
          if (filterType == "ogc") {
            filterParams["FILTER"] = filter;
          }
          if (filterType == "fid")
            filterParams["FEATUREID"] = filter;
          }
          // merge the new filter definitions
          map.getLayers().forEach(function(lyr) {
            lyr.getSource().updateParams(filterParams);
          });
        }

        function resetFilter() {
          if (!supportsFiltering) {
            return;
          }
          document.getElementById('filter').value = "";
          updateFilter();
        }

        // shows/hide the control panel
        function toggleControlPanel(){
          var toolbar = document.getElementById("toolbar");
          if (toolbar.style.display == "none") {
            toolbar.style.display = "block";
          }
          else {
            toolbar.style.display = "none";
          }
          map.updateSize()
        }

    </script>
  </body>
</html>

Bạn đang gặp 3 vấn đề chính:
1.  **"Chọn xanh hết"**: Do style highlight có màu nền (fill) che mất bản đồ. Tôi sẽ đổi thành chỉ hiện viền (stroke) và ruột trong suốt.
2.  **"Load lâu"**: Do request phải đi qua Proxy. Tôi sẽ thêm hiệu ứng con chuột `wait` (đồng hồ cát/xoay) để bạn biết hệ thống đang xử lý.
3.  **"Chuột dấu cộng / Không hiện Popup"**: Tôi sẽ bỏ icon dấu cộng, và quan trọng nhất là sửa lỗi logic `setPosition` của Popup để nó hiện ngay tại điểm click.

Dưới đây là mã sửa lỗi:

# Updated files:

## pages/MapPage.tsx

- **Giao diện**: Bỏ class `cursor-crosshair` (trở về chuột bình thường).
- **Hiệu năng**: Thêm `document.body.style.cursor = 'wait'` khi click để báo đang tải.
- **Sửa lỗi Popup**: Thêm dòng `popupOverlay.current.setPosition(evt.coordinate)` để đảm bảo Popup nhảy đúng chỗ click.
- **Thẩm mỹ**: Chỉnh lại Style highlight thành **trong suốt (no fill)**, chỉ có viền màu đỏ đậm để không che mất bản đồ "xanh lè".

```tsx
import React, { useEffect, useRef, useState } from 'react';
import { User, LandParcel, UserRole, WMSLayerConfig } from '../types';
import { gisService, API_URL } from '../services/mockBackend';
import { Layers, MousePointer2, Save, Trash2, X, AlertTriangle, CheckCircle, MapPin, Globe, Map as MapIcon, Eye, EyeOff, Info, List, FileText, WifiOff, RefreshCw, Search, Loader2, Printer, Navigation, Crosshair, ChevronDown, Table as TableIcon } from 'lucide-react';
import { jsPDF } from "jspdf";
import html2canvas from "html2canvas";
import proj4 from "proj4";

// OpenLayers uses global 'ol' from CDN
declare const ol: any;

// --- CẤU HÌNH HỆ TỌA ĐỘ VN-2000 ---
proj4.defs("EPSG:9210", "+proj=tmerc +lat_0=0 +lon_0=105.75 +k=0.9999 +x_0=500000 +y_0=0 +ellps=WGS84 +towgs84=-191.90441429,-39.30318279,-111.45032835,0.00928836,0.01975479,-0.00427372,0.252906278 +units=m +no_defs");

interface MapPageProps {
  user: User | null;
}

const MapPage: React.FC<MapPageProps> = ({ user }) => {
  const mapElement = useRef<HTMLDivElement>(null);
  const mapInstance = useRef<any>(null);
  const popupElement = useRef<HTMLDivElement>(null);
  const popupOverlay = useRef<any>(null);

  // Layer Refs
  const osmLayer = useRef<any>(null);
  const googleLayer = useRef<any>(null);
  const vietbandoLayer = useRef<any>(null);
  const wmsLayerGroup = useRef<any>(null);
  const vectorLayer = useRef<any>(null); // For local parcels
  const highlightLayer = useRef<any>(null); // For selection highlight

  // State
  const [selectedParcel, setSelectedParcel] = useState<LandParcel | null>(null);
  const [isEditing, setIsEditing] = useState(false);
  const [formData, setFormData] = useState<any>({});

  // Search State
  const [searchQuery, setSearchQuery] = useState('');
  const [searchResults, setSearchResults] = useState<LandParcel[]>([]);
  const [isSearching, setIsSearching] = useState(false);
  const [isSearchOpen, setIsSearchOpen] = useState(false);

  // Layer Control State
  const [activeBaseLayer, setActiveBaseLayer] = useState<'OSM' | 'GOOGLE' | 'VIETBANDO'>('OSM');
  const [availableLayers, setAvailableLayers] = useState<WMSLayerConfig[]>([]);
  const [visibleLayerIds, setVisibleLayerIds] = useState<string[]>([]);
  const [isLayerMenuOpen, setIsLayerMenuOpen] = useState(false);

  const [isGeneratingPDF, setIsGeneratingPDF] = useState(false);
  const [isLocating, setIsLocating] = useState(false);
  const [isFetchingInfo, setIsFetchingInfo] = useState(false);
  const [fetchError, setFetchError] = useState<string | null>(null);

  // Print Template Refs
  const printTemplateRef = useRef<HTMLDivElement>(null);
  const parcelCanvasRef = useRef<HTMLCanvasElement>(null);
  const [geometryPoints, setGeometryPoints] = useState<any[]>([]);

  // 1. Initial Load of Layers Config
  useEffect(() => {
      const fetchLayers = async () => {
          try {
              const layers = await gisService.getLayers();
              setAvailableLayers(layers);
              // Default to first layer visible if none selected
              const defaults = layers.filter(l => l.visible).map(l => l.id);
              if (defaults.length === 0 && layers.length > 0) {
                  setVisibleLayerIds([layers[0].id]);
              } else {
                  setVisibleLayerIds(defaults);
              }
          } catch (e) { console.error("Failed to load layers config", e); }
      };
      fetchLayers();
  }, []);

  // 2. Initialize OpenLayers Map
  useEffect(() => {
      if (!mapElement.current || mapInstance.current) return;
      if (typeof ol === 'undefined') {
          console.error("OpenLayers not loaded!"); 
          return;
      }

      // --- Base Layers ---
      osmLayer.current = new ol.layer.Tile({
          source: new ol.source.OSM(),
          visible: true,
          properties: { id: 'OSM' }
      });

      googleLayer.current = new ol.layer.Tile({
          source: new ol.source.XYZ({
              url: 'https://mt1.google.com/vt/lyrs=y&x={x}&y={y}&z={z}',
              attributions: '© Google Maps'
          }),
          visible: false,
          properties: { id: 'GOOGLE' }
      });

      vietbandoLayer.current = new ol.layer.Tile({
           source: new ol.source.XYZ({
              url: `${API_URL}/api/proxy/vietbando?z={z}&x={x}&y={y}`
           }),
           visible: false,
           properties: { id: 'VIETBANDO' }
      });

      // --- WMS Group (Empty initially) ---
      wmsLayerGroup.current = new ol.layer.Group({
          layers: [],
          zIndex: 10
      });

      // --- Vector Layer (Local Data) ---
      vectorLayer.current = new ol.layer.Vector({
          source: new ol.source.Vector(),
          style: new ol.style.Style({
              stroke: new ol.style.Stroke({ color: '#3b82f6', width: 2 }),
              fill: new ol.style.Fill({ color: 'rgba(59, 130, 246, 0.0)' }) // Transparent fill
          }),
          zIndex: 20
      });

      // --- Highlight Layer (SỬA STYLE: BỎ FILL XANH, CHỈ VIỀN ĐỎ) ---
      highlightLayer.current = new ol.layer.Vector({
          source: new ol.source.Vector(),
          style: new ol.style.Style({
              stroke: new ol.style.Stroke({ color: '#ef4444', width: 3 }), // Viền đỏ đậm
              fill: new ol.style.Fill({ color: 'rgba(255, 255, 255, 0.01)' }), // Trong suốt hoàn toàn
              image: new ol.style.Circle({
                  radius: 6,
                  fill: new ol.style.Fill({ color: '#ef4444' }),
                  stroke: new ol.style.Stroke({ color: '#fff', width: 2 })
              })
          }),
          zIndex: 100
      });

      // --- Create Map ---
      const map = new ol.Map({
          target: mapElement.current,
          layers: [
              osmLayer.current, 
              googleLayer.current, 
              vietbandoLayer.current,
              wmsLayerGroup.current,
              vectorLayer.current,
              highlightLayer.current
          ],
          view: new ol.View({
              center: ol.proj.fromLonLat([106.619, 11.284]), // Convert to EPSG:3857
              zoom: 13
          }),
          controls: ol.control.defaults.defaults({
              zoom: true,
              rotate: false,
              attribution: false
          })
      });

      // --- Popup Overlay ---
      popupOverlay.current = new ol.Overlay({
          element: popupElement.current,
          autoPan: {
            animation: { duration: 250 }
          },
          positioning: 'bottom-center',
          offset: [0, -10]
      });
      map.addOverlay(popupOverlay.current);

      // --- Click Handler (WMS GetFeatureInfo) ---
      map.on('singleclick', async (evt: any) => {
          // UX: Đổi con chuột thành đồng hồ cát
          document.body.style.cursor = 'wait';

          // Reset
          setFetchError(null);
          highlightLayer.current.getSource().clear();

          // 1. Check if we clicked on a vector feature (Local Data)
          let clickedVector = false;
          map.forEachFeatureAtPixel(evt.pixel, (feature: any) => {
               if (feature.get('type') === 'highlight') return; // Ignore highlight itself
               const props = feature.getProperties();
               // Setup popup data for vector
               handleSelectParcel({
                   id: feature.getId(),
                   geometry: null, // geometry handled by OL
                   properties: {
                       ...props,
                       ownerName: props.tenchu || 'Chưa cập nhật',
                       landType: props.loaidat || 'Residential',
                       area: props.dientich || 0,
                       branchId: 'Local Data',
                       planningStatus: 'Safe',
                       so_to: props.sodoto,
                       so_thua: props.sothua
                   }
               });
               // Show popup at click location for vector
               popupOverlay.current.setPosition(evt.coordinate);
               clickedVector = true;
               return true; // stop iteration
          }, { layerFilter: (l: any) => l === vectorLayer.current });

          if (clickedVector) {
              document.body.style.cursor = 'default';
              return;
          }

          // 2. If no vector, try WMS GetFeatureInfo
          const view = map.getView();
          const viewResolution = view.getResolution();
          const viewProjection = view.getProjection();

          // Get the top-most visible WMS layer
          const layers = wmsLayerGroup.current.getLayers().getArray();
          // Iterate backwards to find top-most visible
          let targetSource: any = null;
          let layerConfig: WMSLayerConfig | null = null;

          for (let i = layers.length - 1; i >= 0; i--) {
              const l = layers[i];
              if (l.getVisible()) {
                  targetSource = l.getSource();
                  layerConfig = l.get('config'); // We stored config in property
                  break;
              }
          }

          if (targetSource && layerConfig) {
               setIsFetchingInfo(true);

               // Optional: Highlight point while loading
               // const clickFeature = new ol.Feature(new ol.geom.Point(evt.coordinate));
               // clickFeature.set('type', 'highlight');
               // highlightLayer.current.getSource().addFeature(clickFeature);

               const url = targetSource.getFeatureInfoUrl(
                   evt.coordinate,
                   viewResolution,
                   viewProjection,
                   {
                       'INFO_FORMAT': 'application/json',
                       'FEATURE_COUNT': 1
                   }
               );

               if (url) {
                   // --- FIX CORS: USE BACKEND PROXY ---
                   const proxyUrl = `${API_URL}/api/proxy/forward?url=${encodeURIComponent(url)}`;

                   try {
                       const res = await fetch(proxyUrl);
                       if (!res.ok) throw new Error(`HTTP Error ${res.status}`);
                       const data = await res.json();

                       if (data.features && data.features.length > 0) {
                           const feature = data.features[0];
                           const props = feature.properties || {};

                           // Helper to get attr case-insensitive
                           const getAttr = (keys: string[]) => {
                               for (const k of keys) {
                                   if (props[k] !== undefined && props[k] !== null) return props[k];
                                   const lower = Object.keys(props).find(pk => pk.toLowerCase() === k.toLowerCase());
                                   if (lower) return props[lower];
                               }
                               return null;
                           };

                           // Create mapped object
                           const mappedParcel: LandParcel = {
                               id: feature.id || `wms-${Date.now()}`,
                               geometry: feature.geometry,
                               properties: {
                                    ownerName: getAttr(['tenchu', 'chu', 'owner', 'chusohuu', 'ten_chu']) || 'Chưa cập nhật',
                                    landType: getAttr(['loaidat', 'kyhieumucd', 'loai_dat', 'mdsd']) || 'Residential',
                                    area: Number(getAttr(['dientich', 'dien_tich', 'shape_area', 'area'])) || 0,
                                    pricePerM2: 0,
                                    totalValue: 0,
                                    planningStatus: 'Safe',
                                    branchId: 'WMS Data',
                                    updatedBy: 'GeoServer',
                                    so_to: getAttr(['sohieutoba', 'sodoto', 'shmap', 'so_to', 'map_sheet']),
                                    so_thua: getAttr(['sothututhu', 'sothua', 'shthua', 'so_thua', 'parcel_no']),
                                    address: getAttr(['diachi', 'dia_chi', 'address', 'khu_vuc']),
                                    ...props // Keep all raw props
                               }
                           };

                           // If geometry exists, highlight it
                           if (feature.geometry) {
                               const reader = new ol.format.GeoJSON();
                               const olFeature = reader.readFeature(feature); 

                               // Check extent to see if it needs transform
                               const extent = olFeature.getGeometry().getExtent();
                               // Basic check if coords are lon/lat (small numbers) vs Mercator (huge numbers)
                               // If feature.geometry is already 3857 (from Geoserver), no need transform.
                               // Geoserver typically returns in the requested SRS (EPSG:3857).
                               // But 'readFeature' might assume 4326 if not told otherwise, or feature might lack CRS.
                               // Best bet: Tell readFeature we expect data in view projection if GeoServer respects SRS param.

                               // However, raw GeoJSON often implies 4326. Let's rely on what we requested.
                               // We requested SRS=EPSG:3857 in getFeatureInfoUrl usually.
                               // Let's safe check:

                               highlightLayer.current.getSource().clear(); 
                               highlightLayer.current.getSource().addFeature(olFeature);
                           }

                           handleSelectParcel(mappedParcel);

                           // QUAN TRỌNG: Phải set vị trí Popup sau khi có dữ liệu
                           popupOverlay.current.setPosition(evt.coordinate);

                       } else {
                           // No features
                           setIsEditing(false);
                           setSelectedParcel(null);
                           popupOverlay.current.setPosition(undefined);
                       }
                   } catch (err: any) {
                       console.warn("WMS Fetch Error:", err);
                       // setFetchError(`Lỗi lấy thông tin: ${err.message}`); // Tắt báo lỗi khó chịu nếu chỉ click nhầm
                   } finally {
                       setIsFetchingInfo(false);
                       document.body.style.cursor = 'default';
                   }
               } else {
                   document.body.style.cursor = 'default';
               }
          } else {
              document.body.style.cursor = 'default';
          }
      });

      mapInstance.current = map;

      // Load local parcels (Vector) initially
      loadVectorParcels();

      return () => {
          map.setTarget(undefined);
          mapInstance.current = null;
      };
  }, []);

  // 3. Update Base Layers Visibility
  useEffect(() => {
      if (!mapInstance.current) return;
      osmLayer.current.setVisible(activeBaseLayer === 'OSM');
      googleLayer.current.setVisible(activeBaseLayer === 'GOOGLE');
      vietbandoLayer.current.setVisible(activeBaseLayer === 'VIETBANDO');
  }, [activeBaseLayer]);

  // 4. Update WMS Layers from Config
  useEffect(() => {
      if (!mapInstance.current || !wmsLayerGroup.current) return;

      // Clear existing WMS layers in the group
      wmsLayerGroup.current.getLayers().clear();

      availableLayers.forEach(config => {
          if (visibleLayerIds.includes(config.id)) {
              // Create WMS source
              const source = new ol.source.TileWMS({
                  url: config.url,
                  params: {
                      'LAYERS': config.layers,
                      'TILED': true,
                      'VERSION': '1.1.1', // Use 1.1.1 for better compatibility
                      'FORMAT': 'image/png',
                      'TRANSPARENT': true
                  },
                  serverType: 'geoserver',
                  transition: 0
              });

              const layer = new ol.layer.Tile({
                  source: source,
                  visible: true,
                  properties: { config: config } // Attach config for click handler
              });

              wmsLayerGroup.current.getLayers().push(layer);
          }
      });
  }, [availableLayers, visibleLayerIds]);


  // --- Helper Functions ---

  const loadVectorParcels = async () => {
      try {
          const parcels = await gisService.getParcels(user);
          if (!vectorLayer.current) return;

          const source = vectorLayer.current.getSource();
          source.clear();

          if (parcels.length > 0) {
             const features = new ol.format.GeoJSON().readFeatures({
                 type: "FeatureCollection",
                 features: parcels.map(p => ({
                     type: "Feature",
                     id: p.id,
                     geometry: p.geometry,
                     properties: p.properties
                 }))
             }, {
                 featureProjection: 'EPSG:3857' // Transform to map projection
             });
             source.addFeatures(features);
          }
      } catch (e) { console.error("Vector load failed", e); }
  };

  const handleSelectParcel = (parcel: LandParcel) => {
      setSelectedParcel(parcel);
      setFormData(parcel.properties);
      setIsEditing(true);

      // Show Popup - style block handled by React/CSS, but position handled by OL
      if (popupElement.current) {
          popupElement.current.style.display = 'block';
      }
  };

  const handleInputChange = (field: string, value: any) => {
      const newFormData = { ...formData, [field]: value };
      if (field === 'landType') {
          newFormData.totalValue = gisService.calculatePrice(newFormData.area, value);
      }
      setFormData(newFormData);
  };

  const updateParcelData = async () => {
      // Logic for updating parcel... (Simplified for WMS view focus)
      alert("Tính năng lưu đang được cập nhật cho phiên bản OpenLayers.");
  };

  const handleDelete = () => {
      alert("Tính năng xóa đang được cập nhật cho phiên bản OpenLayers.");
  };

  const handlePlanningCheck = async () => {
      if(!selectedParcel) return;
      const status = await gisService.checkPlanning(selectedParcel);
      setFormData({...formData, planningStatus: status});
  };

  const handleLocateMe = () => {
      setIsLocating(true);
      if (!navigator.geolocation) {
          alert("Không hỗ trợ GPS.");
          setIsLocating(false);
          return;
      }
      navigator.geolocation.getCurrentPosition((pos) => {
          const coords = [pos.coords.longitude, pos.coords.latitude];
          const view = mapInstance.current.getView();
          view.animate({
              center: ol.proj.fromLonLat(coords),
              zoom: 17,
              duration: 1000
          });

          // Add marker
          const marker = new ol.Feature(new ol.geom.Point(ol.proj.fromLonLat(coords)));
          marker.setStyle(new ol.style.Style({
              image: new ol.style.Circle({
                  radius: 8,
                  fill: new ol.style.Fill({color: '#3b82f6'}),
                  stroke: new ol.style.Stroke({color: '#fff', width: 2})
              })
          }));
          highlightLayer.current.getSource().addFeature(marker);
          setIsLocating(false);
      }, () => {
          alert("Không thể lấy vị trí.");
          setIsLocating(false);
      });
  };

  const handleExportPDF = () => {
      alert("Tính năng xuất PDF đang bảo trì.");
  };

  const handleSearch = async (e: React.FormEvent) => {
      e.preventDefault();
      if (!searchQuery.trim()) return;
      setIsSearching(true);
      try {
          const results = await gisService.searchParcels(searchQuery);
          setSearchResults(results);
          if (results.length === 0) alert('Không tìm thấy kết quả nào.');
      } catch (err) { console.error(err); } finally { setIsSearching(false); }
  };

  const handleSelectSearchResult = (parcel: LandParcel) => {
      handleSelectParcel(parcel);
      // Zoom to feature
      const view = mapInstance.current.getView();
      if (parcel.geometry) {
           const format = new ol.format.GeoJSON();
           const feature = format.readFeature({
               type: "Feature", 
               geometry: parcel.geometry
           }, { featureProjection: 'EPSG:3857' });
           const extent = feature.getGeometry().getExtent();
           view.fit(extent, { padding: [50,50,50,50], duration: 1000, maxZoom: 18 });

           highlightLayer.current.getSource().clear();
           highlightLayer.current.getSource().addFeature(feature);

           // Set popup position to center of extent
           popupOverlay.current.setPosition(ol.extent.getCenter(extent));
      }
      setIsSearchOpen(false);
  };

  const canEdit = user && selectedParcel && selectedParcel.properties.branchId !== 'WMS Data' &&
                  (user.role === UserRole.ADMIN || (user.role === UserRole.EDITOR && selectedParcel.properties.branchId === user.branchId));

  const getPlanningStatusLabel = (status: string) => {
    switch(status) {
        case 'Safe': return 'An toàn / Không vướng';
        case 'Planning': return 'Đang quy hoạch';
        case 'Disputed': return 'Đang tranh chấp';
        default: return status;
    }
  };

  const toggleLayer = (layerId: string) => {
      setVisibleLayerIds(prev => {
          if (prev.includes(layerId)) {
              return prev.filter(id => id !== layerId);
          } else {
              return [...prev, layerId];
          }
      });
  };

  return (
    <div className="relative w-full h-full bg-gray-100">
      {/* Map Container - BỎ cursor-crosshair */}
      <div 
        ref={mapElement} 
        className="w-full h-full z-0 cursor-default" 
