      {/* --- POPUP CONTAINER (OPENLAYERS OVERLAY) --- */}
      <div ref={popupElement} className="ol-popup">
         {selectedParcel && (
             <div className="flex flex-col w-full h-full">
                <div className="bg-gray-800 text-white p-3 flex justify-between items-center rounded-t-lg">
                    <h3 className="font-semibold flex items-center gap-2 text-sm"><Info size={16} className="text-blue-400" /> Thông tin Thửa đất</h3>
                    <button onClick={() => {
                        setIsEditing(false);
                        setSelectedParcel(null);
                        popupElement.current!.style.display = 'none';
                        if(highlightLayer.current) highlightLayer.current.getSource().clear();
