           {isSearchOpen && (
               <div className="bg-white/95 backdrop-blur-sm p-4 rounded-xl shadow-2xl border border-gray-200 w-80 animate-in slide-in-from-left-4 duration-200">
                   <form onSubmit={handleSearch} className="flex gap-2">
                       <input className="flex-1 bg-gray-100 border border-gray-300 rounded px-3 py-2 text-sm outline-none focus:border-blue-500" placeholder="Số tờ, số thửa, tên..." value={searchQuery} onChange={(e) => setSearchQuery(e.target.value)} autoFocus />
                       <button type="submit" className="bg-blue-600 text-white p-2 rounded hover:bg-blue-500">
                           {isSearching ? <Loader2 size={16} className="animate-spin"/> : <Search size={16} />}
                       </button>
                   </form>
                   <div className="mt-4 max-h-60 overflow-y-auto custom-scrollbar space-y-2">
                       {searchResults.map(parcel => (
                           <div key={parcel.id} onClick={() => handleSelectSearchResult(parcel)} className="p-3 rounded bg-gray-50 hover:bg-blue-50 border border-gray-100 cursor-pointer transition-colors group">
                               <div className="font-bold text-gray-800 text-sm">Tờ: {parcel.properties['so_to']||'?'} - Thửa: {parcel.properties['so_thua']||'?'}</div>
                               <div className="text-xs text-gray-500 mt-1 truncate">Chủ: {parcel.properties.ownerName}</div>
                           </div>
                       ))}
                       {searchResults.length === 0 && !isSearching && searchQuery && <div className="text-center text-gray-400 text-sm py-4 italic">Không có kết quả.</div>}
                   </div>
               </div>
           )}
      </div>

      {/* Layer Control */}
      <div className="absolute top-4 right-4 z-[400] flex flex-col items-end gap-2">
          <button className={`p-3 bg-white rounded-lg shadow-lg hover:bg-gray-50 text-gray-700 transition-all ${isLayerMenuOpen ? 'bg-blue-50 text-blue-600 ring-2 ring-blue-300' : ''}`} onClick={() => setIsLayerMenuOpen(!isLayerMenuOpen)}>
              <Layers size={24} />
          </button>
          {isLayerMenuOpen && (
              <div className="bg-white/95 backdrop-blur-sm p-4 rounded-xl shadow-2xl border border-gray-200 w-72 animate-in slide-in-from-right-10 duration-200">
                  <h4 className="text-xs font-bold text-gray-500 uppercase mb-3 tracking-wider">Nền Bản đồ</h4>
                  <div className="space-y-2 mb-4">
                      {['OSM', 'GOOGLE', 'VIETBANDO'].map((type: any) => (
                          <div key={type} onClick={() => setActiveBaseLayer(type)} className={`flex items-center gap-3 p-2 rounded cursor-pointer transition-colors ${activeBaseLayer === type ? 'bg-blue-50 border border-blue-200' : 'hover:bg-gray-100 border border-transparent'}`}>
                              <div className={`w-4 h-4 rounded-full border flex items-center justify-center ${activeBaseLayer === type ? 'border-blue-600' : 'border-gray-400'}`}>{activeBaseLayer === type && <div className="w-2 h-2 bg-blue-600 rounded-full" />}</div>
                              <span className="text-sm font-medium text-gray-700">{type}</span>
                          </div>
                      ))}
                  </div>
                  <div className="border-t border-gray-100 my-3"></div>
                  <h4 className="text-xs font-bold text-gray-500 uppercase mb-3 tracking-wider">Lớp Dữ liệu (WMS)</h4>
                  <div className="space-y-2">
                      {availableLayers.length === 0 ? <div className="text-xs text-gray-400 italic">Trống...</div> : availableLayers.map(l => (
                            <div key={l.id} onClick={() => toggleLayer(l.id)} className="flex items-center justify-between p-2 rounded hover:bg-gray-50 cursor-pointer">
                                <div className="flex items-center gap-3"><MapPin size={18} className={visibleLayerIds.includes(l.id) ? "text-orange-600" : "text-gray-400"} /><span className="text-sm font-medium text-gray-700">{l.name}</span></div>
                                <button className={`text-gray-400 ${visibleLayerIds.includes(l.id) ? 'text-blue-600' : ''}`}>{visibleLayerIds.includes(l.id) ? <Eye size={18} /> : <EyeOff size={18} />}</button>
                            </div>
                      ))}
                  </div>
              </div>
          )}
      </div>

      <div className="absolute bottom-24 right-4 z-[400]">
          <button onClick={handleLocateMe} className="p-3 bg-white rounded-lg shadow-lg hover:bg-gray-50 text-gray-700" title="Vị trí của tôi">
              {isLocating ? <Loader2 size={24} className="animate-spin text-blue-600"/> : <Crosshair size={24} />}
          </button>
      </div>

    </div>
  );
};

export default MapPage;

Bạn đang gặp vấn đề là lớp `vectorLayer` (Dữ liệu Vector cục bộ) đang tự động tải toàn bộ dữ liệu thửa đất lên và vẽ đè lên bản đồ WMS với viền màu xanh dương (`#3b82f6`). Điều này gây rối mắt và làm nặng bản đồ.

Giải pháp:
1.  **Tắt việc tải dữ liệu Vector toàn cục**: Chỉ sử dụng lớp WMS để hiển thị bản đồ nền (nhẹ và chuẩn từ GeoServer).
2.  **Chỉ hiển thị Highlight**: Chỉ khi bạn click vào thửa đất hoặc tìm kiếm, hệ thống mới vẽ viền đỏ (Highlight) cho riêng thửa đó.

Dưới đây là mã cập nhật cho `pages/MapPage.tsx`:

# Updated files:

## pages/MapPage.tsx

- **Bỏ `loadVectorParcels()`**: Ngăn không cho ứng dụng tải và vẽ "lưới xanh" của toàn bộ dữ liệu lên bản đồ khi khởi động.
- **Tinh chỉnh `highlightLayer`**: Viền đỏ đậm, rõ ràng hơn để nổi bật thửa đang chọn.
- **Giữ nguyên logic WMS**: Đảm bảo click vào bản đồ vẫn gọi API lấy thông tin chính xác.

```tsx
import React, { useEffect, useRef, useState } from 'react';
import { User, LandParcel, UserRole, WMSLayerConfig } from '../types';
import { gisService, API_URL } from '../services/mockBackend';
import { Layers, MousePointer2, Save, Trash2, X, AlertTriangle, CheckCircle, MapPin, Globe, Map as MapIcon, Eye, EyeOff, Info, List, FileText, WifiOff, RefreshCw, Search, Loader2, Printer, Navigation, Crosshair, ChevronDown, Table as TableIcon } from 'lucide-react';
import { jsPDF } from "jspdf";
import html2canvas from "html2canvas";
import proj4 from "proj4";

// OpenLayers uses global 'ol' from CDN
declare const ol: any;

// --- CẤU HÌNH HỆ TỌA ĐỘ VN-2000 ---
proj4.defs("EPSG:9210", "+proj=tmerc +lat_0=0 +lon_0=105.75 +k=0.9999 +x_0=500000 +y_0=0 +ellps=WGS84 +towgs84=-191.90441429,-39.30318279,-111.45032835,0.00928836,0.01975479,-0.00427372,0.252906278 +units=m +no_defs");

interface MapPageProps {
  user: User | null;
}

const MapPage: React.FC<MapPageProps> = ({ user }) => {
  const mapElement = useRef<HTMLDivElement>(null);
  const mapInstance = useRef<any>(null);
  const popupElement = useRef<HTMLDivElement>(null);
  const popupOverlay = useRef<any>(null);

  // Layer Refs
  const osmLayer = useRef<any>(null);
  const googleLayer = useRef<any>(null);
  const vietbandoLayer = useRef<any>(null);
  const wmsLayerGroup = useRef<any>(null);
  const vectorLayer = useRef<any>(null); // For local parcels
  const highlightLayer = useRef<any>(null); // For selection highlight

  // State
  const [selectedParcel, setSelectedParcel] = useState<LandParcel | null>(null);
  const [isEditing, setIsEditing] = useState(false);
  const [formData, setFormData] = useState<any>({});

  // Search State
  const [searchQuery, setSearchQuery] = useState('');
  const [searchResults, setSearchResults] = useState<LandParcel[]>([]);
  const [isSearching, setIsSearching] = useState(false);
  const [isSearchOpen, setIsSearchOpen] = useState(false);

  // Layer Control State
  const [activeBaseLayer, setActiveBaseLayer] = useState<'OSM' | 'GOOGLE' | 'VIETBANDO'>('OSM');
  const [availableLayers, setAvailableLayers] = useState<WMSLayerConfig[]>([]);
  const [visibleLayerIds, setVisibleLayerIds] = useState<string[]>([]);
  const [isLayerMenuOpen, setIsLayerMenuOpen] = useState(false);

  const [isGeneratingPDF, setIsGeneratingPDF] = useState(false);
  const [isLocating, setIsLocating] = useState(false);
  const [isFetchingInfo, setIsFetchingInfo] = useState(false);
  const [fetchError, setFetchError] = useState<string | null>(null);

  // Print Template Refs
  const printTemplateRef = useRef<HTMLDivElement>(null);
  const parcelCanvasRef = useRef<HTMLCanvasElement>(null);
  const [geometryPoints, setGeometryPoints] = useState<any[]>([]);

  // 1. Initial Load of Layers Config
  useEffect(() => {
      const fetchLayers = async () => {
          try {
              const layers = await gisService.getLayers();
              setAvailableLayers(layers);
              // Default to first layer visible if none selected
              const defaults = layers.filter(l => l.visible).map(l => l.id);
              if (defaults.length === 0 && layers.length > 0) {
                  setVisibleLayerIds([layers[0].id]);
              } else {
                  setVisibleLayerIds(defaults);
              }
          } catch (e) { console.error("Failed to load layers config", e); }
      };
      fetchLayers();
  }, []);

  // 2. Initialize OpenLayers Map
  useEffect(() => {
      if (!mapElement.current || mapInstance.current) return;
      if (typeof ol === 'undefined') {
          console.error("OpenLayers not loaded!"); 
          return;
      }

      // --- Base Layers ---
      osmLayer.current = new ol.layer.Tile({
          source: new ol.source.OSM(),
          visible: true,
          properties: { id: 'OSM' }
      });

      googleLayer.current = new ol.layer.Tile({
          source: new ol.source.XYZ({
              url: 'https://mt1.google.com/vt/lyrs=y&x={x}&y={y}&z={z}',
              attributions: '© Google Maps'
          }),
          visible: false,
          properties: { id: 'GOOGLE' }
      });

      vietbandoLayer.current = new ol.layer.Tile({
           source: new ol.source.XYZ({
              url: `${API_URL}/api/proxy/vietbando?z={z}&x={x}&y={y}`
           }),
           visible: false,
           properties: { id: 'VIETBANDO' }
      });

      // --- WMS Group (Empty initially) ---
      wmsLayerGroup.current = new ol.layer.Group({
          layers: [],
          zIndex: 10
      });

      // --- Vector Layer (Local Data) ---
      // Tắt vẽ viền xanh mặc định (Dữ liệu cục bộ)
      vectorLayer.current = new ol.layer.Vector({
          source: new ol.source.Vector(),
          style: new ol.style.Style({
              // stroke: new ol.style.Stroke({ color: '#3b82f6', width: 2 }), // <-- DÒNG GÂY RA VIỀN XANH
              stroke: null, // Tắt viền
              fill: null // Tắt nền
          }),
          visible: false, // Ẩn luôn layer này đi
          zIndex: 20
      });

      // --- Highlight Layer (CHỈ HIỆN KHI CHỌN) ---
      highlightLayer.current = new ol.layer.Vector({
          source: new ol.source.Vector(),
          style: new ol.style.Style({
              stroke: new ol.style.Stroke({ color: '#ef4444', width: 3 }), // Viền đỏ đậm
              fill: new ol.style.Fill({ color: 'rgba(255, 255, 255, 0.01)' }), // Trong suốt
              image: new ol.style.Circle({
                  radius: 6,
                  fill: new ol.style.Fill({ color: '#ef4444' }),
                  stroke: new ol.style.Stroke({ color: '#fff', width: 2 })
              })
          }),
          zIndex: 100
      });

      // --- Create Map ---
      const map = new ol.Map({
          target: mapElement.current,
          layers: [
              osmLayer.current, 
              googleLayer.current, 
              vietbandoLayer.current,
              wmsLayerGroup.current,
              // vectorLayer.current, // Không cần add layer vector nữa nếu không muốn hiện
              highlightLayer.current
          ],
          view: new ol.View({
              center: ol.proj.fromLonLat([106.619, 11.284]), // Convert to EPSG:3857
              zoom: 13
          }),
          controls: ol.control.defaults.defaults({
              zoom: true,
              rotate: false,
              attribution: false
          })
      });

      // --- Popup Overlay ---
      popupOverlay.current = new ol.Overlay({
          element: popupElement.current,
          autoPan: {
            animation: { duration: 250 }
          },
          positioning: 'bottom-center',
          offset: [0, -10]
      });
      map.addOverlay(popupOverlay.current);

      // --- Click Handler (WMS GetFeatureInfo) ---
      map.on('singleclick', async (evt: any) => {
          // UX: Đổi con chuột thành đồng hồ cát
          document.body.style.cursor = 'wait';

          // Reset
          setFetchError(null);
          highlightLayer.current.getSource().clear();

          // Lấy thông tin WMS (GetFeatureInfo)
          const view = map.getView();
          const viewResolution = view.getResolution();
          const viewProjection = view.getProjection();

          // Tìm lớp WMS đang hiển thị trên cùng
          const layers = wmsLayerGroup.current.getLayers().getArray();
          let targetSource: any = null;
          let layerConfig: WMSLayerConfig | null = null;

          for (let i = layers.length - 1; i >= 0; i--) {
              const l = layers[i];
              if (l.getVisible()) {
                  targetSource = l.getSource();
                  layerConfig = l.get('config'); 
                  break;
              }
          }

          if (targetSource && layerConfig) {
               setIsFetchingInfo(true);

               const url = targetSource.getFeatureInfoUrl(
                   evt.coordinate,
                   viewResolution,
                   viewProjection,
                   {
                       'INFO_FORMAT': 'application/json',
                       'FEATURE_COUNT': 1
                   }
               );

               if (url) {
                   // Sử dụng Proxy để tránh CORS
                   const proxyUrl = `${API_URL}/api/proxy/forward?url=${encodeURIComponent(url)}`;

                   try {
                       const res = await fetch(proxyUrl);
                       if (!res.ok) throw new Error(`HTTP Error ${res.status}`);
                       const data = await res.json();

                       if (data.features && data.features.length > 0) {
                           const feature = data.features[0];
                           const props = feature.properties || {};

                           const getAttr = (keys: string[]) => {
                               for (const k of keys) {
                                   if (props[k] !== undefined && props[k] !== null) return props[k];
                                   const lower = Object.keys(props).find(pk => pk.toLowerCase() === k.toLowerCase());
                                   if (lower) return props[lower];
                               }
                               return null;
                           };

                           const mappedParcel: LandParcel = {
                               id: feature.id || `wms-${Date.now()}`,
                               geometry: feature.geometry,
                               properties: {
                                    ownerName: getAttr(['tenchu', 'chu', 'owner', 'chusohuu', 'ten_chu']) || 'Chưa cập nhật',
                                    landType: getAttr(['loaidat', 'kyhieumucd', 'loai_dat', 'mdsd']) || 'Residential',
                                    area: Number(getAttr(['dientich', 'dien_tich', 'shape_area', 'area'])) || 0,
                                    pricePerM2: 0,
                                    totalValue: 0,
                                    planningStatus: 'Safe',
                                    branchId: 'WMS Data',
                                    updatedBy: 'GeoServer',
                                    so_to: getAttr(['sohieutoba', 'sodoto', 'shmap', 'so_to', 'map_sheet']),
                                    so_thua: getAttr(['sothututhu', 'sothua', 'shthua', 'so_thua', 'parcel_no']),
                                    address: getAttr(['diachi', 'dia_chi', 'address', 'khu_vuc']),
                                    ...props 
                               }
                           };

                           // VẼ HIGHLIGHT MÀU ĐỎ LÊN THỬA ĐƯỢC CHỌN
                           if (feature.geometry) {
                               const reader = new ol.format.GeoJSON();
                               const olFeature = reader.readFeature(feature); 
                               highlightLayer.current.getSource().clear(); 
                               highlightLayer.current.getSource().addFeature(olFeature);
                           }

                           handleSelectParcel(mappedParcel);

                           // Hiện Popup
                           popupOverlay.current.setPosition(evt.coordinate);

                       } else {
                           // Click ra ngoài -> Tắt popup
                           setIsEditing(false);
                           setSelectedParcel(null);
                           popupOverlay.current.setPosition(undefined);
                       }
                   } catch (err: any) {
                       console.warn("WMS Fetch Error:", err);
                   } finally {
                       setIsFetchingInfo(false);
                       document.body.style.cursor = 'default';
                   }
               } else {
                   document.body.style.cursor = 'default';
               }
          } else {
              document.body.style.cursor = 'default';
          }
      });

      mapInstance.current = map;

      // QUAN TRỌNG: KHÔNG GỌI loadVectorParcels() ĐỂ TRÁNH VẼ LƯỚI XANH TOÀN BỘ
      // loadVectorParcels(); 

      return () => {
          map.setTarget(undefined);
          mapInstance.current = null;
      };
  }, []);

  // 3. Update Base Layers Visibility
  useEffect(() => {
      if (!mapInstance.current) return;
      osmLayer.current.setVisible(activeBaseLayer === 'OSM');
      googleLayer.current.setVisible(activeBaseLayer === 'GOOGLE');
      vietbandoLayer.current.setVisible(activeBaseLayer === 'VIETBANDO');
  }, [activeBaseLayer]);

  // 4. Update WMS Layers from Config
  useEffect(() => {
      if (!mapInstance.current || !wmsLayerGroup.current) return;

      // Clear existing WMS layers in the group
      wmsLayerGroup.current.getLayers().clear();

      availableLayers.forEach(config => {
          if (visibleLayerIds.includes(config.id)) {
              // Create WMS source
              const source = new ol.source.TileWMS({
                  url: config.url,
                  params: {
                      'LAYERS': config.layers,
                      'TILED': true,
                      'VERSION': '1.1.1', // Use 1.1.1 for better compatibility
                      'FORMAT': 'image/png',
                      'TRANSPARENT': true
                  },
                  serverType: 'geoserver',
                  transition: 0
              });

              const layer = new ol.layer.Tile({
                  source: source,
                  visible: true,
                  properties: { config: config } // Attach config for click handler
              });

              wmsLayerGroup.current.getLayers().push(layer);
          }
      });
  }, [availableLayers, visibleLayerIds]);


  // --- Helper Functions ---

  const loadVectorParcels = async () => {
      // Hàm này hiện không được gọi tự động nữa
      try {
          const parcels = await gisService.getParcels(user);
          if (!vectorLayer.current) return;

          const source = vectorLayer.current.getSource();
          source.clear();

          if (parcels.length > 0) {
             const features = new ol.format.GeoJSON().readFeatures({
                 type: "FeatureCollection",
                 features: parcels.map(p => ({
                     type: "Feature",
                     id: p.id,
                     geometry: p.geometry,
                     properties: p.properties
                 }))
             }, {
                 featureProjection: 'EPSG:3857' // Transform to map projection
             });
             source.addFeatures(features);
          }
      } catch (e) { console.error("Vector load failed", e); }
  };

  const handleSelectParcel = (parcel: LandParcel) => {
      setSelectedParcel(parcel);
      setFormData(parcel.properties);
      setIsEditing(true);

      // Show Popup - style block handled by React/CSS, but position handled by OL
      if (popupElement.current) {
          popupElement.current.style.display = 'block';
      }
  };

  const handleInputChange = (field: string, value: any) => {
      const newFormData = { ...formData, [field]: value };
      if (field === 'landType') {
          newFormData.totalValue = gisService.calculatePrice(newFormData.area, value);
      }
      setFormData(newFormData);
  };

  const updateParcelData = async () => {
      // Logic for updating parcel... (Simplified for WMS view focus)
      alert("Tính năng lưu đang được cập nhật cho phiên bản OpenLayers.");
  };

  const handleDelete = () => {
      alert("Tính năng xóa đang được cập nhật cho phiên bản OpenLayers.");
  };

  const handlePlanningCheck = async () => {
      if(!selectedParcel) return;
      const status = await gisService.checkPlanning(selectedParcel);
      setFormData({...formData, planningStatus: status});
  };

  const handleLocateMe = () => {
      setIsLocating(true);
      if (!navigator.geolocation) {
          alert("Không hỗ trợ GPS.");
          setIsLocating(false);
          return;
      }
      navigator.geolocation.getCurrentPosition((pos) => {
          const coords = [pos.coords.longitude, pos.coords.latitude];
          const view = mapInstance.current.getView();
          view.animate({
              center: ol.proj.fromLonLat(coords),
              zoom: 17,
              duration: 1000
          });

          // Add marker
          const marker = new ol.Feature(new ol.geom.Point(ol.proj.fromLonLat(coords)));
          marker.setStyle(new ol.style.Style({
              image: new ol.style.Circle({
                  radius: 8,
                  fill: new ol.style.Fill({color: '#3b82f6'}),
                  stroke: new ol.style.Stroke({color: '#fff', width: 2})
              })
          }));
          highlightLayer.current.getSource().addFeature(marker);
          setIsLocating(false);
      }, () => {
          alert("Không thể lấy vị trí.");
          setIsLocating(false);
      });
  };

  const handleExportPDF = () => {
      alert("Tính năng xuất PDF đang bảo trì.");
  };

  const handleSearch = async (e: React.FormEvent) => {
      e.preventDefault();
      if (!searchQuery.trim()) return;
      setIsSearching(true);
      try {
          const results = await gisService.searchParcels(searchQuery);
          setSearchResults(results);
          if (results.length === 0) alert('Không tìm thấy kết quả nào.');
      } catch (err) { console.error(err); } finally { setIsSearching(false); }
  };

  const handleSelectSearchResult = (parcel: LandParcel) => {
      handleSelectParcel(parcel);
      // Zoom to feature
      const view = mapInstance.current.getView();
      if (parcel.geometry) {
           const format = new ol.format.GeoJSON();
           const feature = format.readFeature({
               type: "Feature", 
               geometry: parcel.geometry
           }, { featureProjection: 'EPSG:3857' });
           const extent = feature.getGeometry().getExtent();
           view.fit(extent, { padding: [50,50,50,50], duration: 1000, maxZoom: 18 });

           highlightLayer.current.getSource().clear();
           highlightLayer.current.getSource().addFeature(feature);

           // Set popup position to center of extent
           popupOverlay.current.setPosition(ol.extent.getCenter(extent));
      }
      setIsSearchOpen(false);
  };

  const canEdit = user && selectedParcel && selectedParcel.properties.branchId !== 'WMS Data' &&
                  (user.role === UserRole.ADMIN || (user.role === UserRole.EDITOR && selectedParcel.properties.branchId === user.branchId));

  const getPlanningStatusLabel = (status: string) => {
    switch(status) {
        case 'Safe': return 'An toàn / Không vướng';
        case 'Planning': return 'Đang quy hoạch';
        case 'Disputed': return 'Đang tranh chấp';
        default: return status;
    }
  };

  const toggleLayer = (layerId: string) => {
      setVisibleLayerIds(prev => {
          if (prev.includes(layerId)) {
              return prev.filter(id => id !== layerId);
          } else {
              return [...prev, layerId];
          }
      });
  };

  return (
    <div className="relative w-full h-full bg-gray-100">
      {/* Map Container - BỎ cursor-crosshair */}
      <div 
        ref={mapElement} 
        className="w-full h-full z-0 cursor-default" 
      />

      {/* --- POPUP CONTAINER (OPENLAYERS OVERLAY) --- */}
      <div ref={popupElement} className="ol-popup">
         {selectedParcel && (
             <div className="flex flex-col w-full h-full">
                <div className="bg-gray-800 text-white p-3 flex justify-between items-center rounded-t-lg">
                    <h3 className="font-semibold flex items-center gap-2 text-sm"><Info size={16} className="text-blue-400" /> Thông tin Thửa đất</h3>
                    <button onClick={() => {
                        setIsEditing(false);
                        setSelectedParcel(null);
                        popupElement.current!.style.display = 'none';
                        if(highlightLayer.current) highlightLayer.current.getSource().clear();
                        popupOverlay.current.setPosition(undefined); // Hide Overlay
                    }} className="hover:bg-gray-700 rounded p-1"><X size={16} /></button>
                </div>
                <div className="p-4 space-y-3 max-h-[60vh] overflow-y-auto custom-scrollbar">
                     {/* Info Fields */}
                     <div className="bg-blue-50 p-2 rounded border border-blue-100 mb-2">
                        <div className="flex justify-between items-center mb-1">
                            <span className="text-xs uppercase font-bold text-blue-800">Tờ bản đồ</span>
                            <span className="font-mono font-bold text-lg text-blue-700">{formData.so_to || '?'}</span>
                        </div>
                        <div className="flex justify-between items-center">
                            <span className="text-xs uppercase font-bold text-blue-800">Số thửa</span>
                            <span className="font-mono font-bold text-lg text-blue-700">{formData.so_thua || '?'}</span>
                        </div>
                     </div>

                     <div>
                        <label className="text-xs text-gray-500 font-bold uppercase">Chủ sở hữu</label>
                        <input className="w-full border-b border-gray-300 py-1 text-sm font-semibold text-gray-800 bg-transparent outline-none" value={formData.ownerName} readOnly />
                     </div>
                     <div>
                        <label className="text-xs text-gray-500 font-bold uppercase">Địa chỉ</label>
                        <div className="text-sm text-gray-700">{formData.address || 'Chưa cập nhật'}</div>
                     </div>
                     <div className="grid grid-cols-2 gap-4">
                        <div>
                            <label className="text-xs text-gray-500 font-bold uppercase">Diện tích (m²)</label>
                            <div className="text-sm font-mono">{formData.area?.toLocaleString()}</div>
                        </div>
                         <div>
                            <label className="text-xs text-gray-500 font-bold uppercase">Loại đất</label>
                            <div className="text-sm">{formData.landType}</div>
                        </div>
                     </div>

                     {/* Raw Attributes Table */}
                     <details className="group border border-gray-200 rounded-lg bg-gray-50 mt-2">
                        <summary className="flex justify-between items-center cursor-pointer p-2 font-medium text-gray-700 hover:bg-gray-100 select-none text-xs">
                            <div className="flex items-center gap-2"><TableIcon size={14}/> Tất cả thuộc tính</div>
                            <ChevronDown size={14} className="text-gray-400 group-open:rotate-180 transition-transform"/>
                        </summary>
                        <div className="p-0 border-t border-gray-200 overflow-x-auto">
                            <table className="w-full text-[10px] text-left">
                                <tbody className="divide-y divide-gray-200">
                                    {Object.entries(selectedParcel.properties)
                                        .filter(([k]) => !['geometry', 'bbox', 'crs'].includes(k))
                                        .map(([key, val], idx) => (
                                        <tr key={idx} className="hover:bg-white">
                                            <td className="p-2 font-bold text-gray-500 bg-gray-50 w-1/3 break-words">{key}</td>
                                            <td className="p-2 text-gray-800 break-all">{typeof val === 'object' ? JSON.stringify(val) : String(val)}</td>
                                        </tr>
                                    ))}
                                </tbody>
                            </table>
                        </div>
                    </details>

                     {canEdit && (
                        <div className="flex gap-2 pt-2 border-t mt-2">
                            <button className="flex-1 bg-blue-600 text-white py-1.5 rounded text-sm hover:bg-blue-700">Chỉnh sửa</button>
                        </div>
                     )}
                </div>
             </div>
         )}
      </div>

      {/* --- UI OVERLAYS (Buttons, Loading, etc) --- */}

      {/* Error Message */}
      {fetchError && (
          <div className="absolute top-4 left-1/2 transform -translate-x-1/2 z-[1000] bg-red-900/90 backdrop-blur-sm text-white px-6 py-4 rounded-lg shadow-2xl border border-red-500 max-w-lg flex flex-col gap-2 animate-in slide-in-from-top-4">
              <div className="flex items-center gap-2 text-red-300 font-bold"><WifiOff size={20} /> Lỗi truy vấn dữ liệu</div>
              <p className="text-sm text-gray-200 whitespace-pre-line">{fetchError}</p>
              <button onClick={() => setFetchError(null)} className="mt-2 w-full bg-white text-red-900 font-bold py-2 rounded hover:bg-gray-200 flex items-center justify-center gap-2">
                  <X size={16} /> Đóng
              </button>
          </div>
      )}

      {/* Loading Indicator - Thêm hiệu ứng load rõ ràng hơn */}
      {isFetchingInfo && (
          <div className="absolute top-1/2 left-1/2 transform -translate-x-1/2 -translate-y-1/2 z-[1000] bg-blue-900/90 backdrop-blur px-6 py-4 rounded-xl flex flex-col items-center gap-3 text-white shadow-2xl border border-blue-500 animate-in fade-in zoom-in duration-200">
               <Loader2 className="animate-spin text-blue-400" size={32} />
               <span className="text-sm font-bold">Đang tải thông tin thửa đất...</span>
          </div>
      )}

      {/* Search Box */}
      <div className="absolute top-4 left-16 z-[400] flex flex-col gap-2">
           <button onClick={() => setIsSearchOpen(!isSearchOpen)} className={`p-3 bg-white rounded-lg shadow-lg hover:bg-gray-50 text-gray-700 transition-all ${isSearchOpen ? 'bg-blue-600 text-white hover:bg-blue-500' : ''}`} title="Tìm kiếm">
               <Search size={24} />
           </button>
           {isSearchOpen && (
               <div className="bg-white/95 backdrop-blur-sm p-4 rounded-xl shadow-2xl border border-gray-200 w-80 animate-in slide-in-from-left-4 duration-200">
                   <form onSubmit={handleSearch} className="flex gap-2">
                       <input className="flex-1 bg-gray-100 border border-gray-300 rounded px-3 py-2 text-sm outline-none focus:border-blue-500" placeholder="Số tờ, số thửa, tên..." value={searchQuery} onChange={(e) => setSearchQuery(e.target.value)} autoFocus />
                       <button type="submit" className="bg-blue-600 text-white p-2 rounded hover:bg-blue-500">
                           {isSearching ? <Loader2 size={16} className="animate-spin"/> : <Search size={16} />}
                       </button>
                   </form>
                   <div className="mt-4 max-h-60 overflow-y-auto custom-scrollbar space-y-2">
                       {searchResults.map(parcel => (
                           <div key={parcel.id} onClick={() => handleSelectSearchResult(parcel)} className="p-3 rounded bg-gray-50 hover:bg-blue-50 border border-gray-100 cursor-pointer transition-colors group">
                               <div className="font-bold text-gray-800 text-sm">Tờ: {parcel.properties['so_to']||'?'} - Thửa: {parcel.properties['so_thua']||'?'}</div>
                               <div className="text-xs text-gray-500 mt-1 truncate">Chủ: {parcel.properties.ownerName}</div>
                           </div>
                       ))}
                       {searchResults.length === 0 && !isSearching && searchQuery && <div className="text-center text-gray-400 text-sm py-4 italic">Không có kết quả.</div>}
                   </div>
               </div>
           )}
      </div>

      {/* Layer Control */}
      <div className="absolute top-4 right-4 z-[400] flex flex-col items-end gap-2">
          <button className={`p-3 bg-white rounded-lg shadow-lg hover:bg-gray-50 text-gray-700 transition-all ${isLayerMenuOpen ? 'bg-blue-50 text-blue-600 ring-2 ring-blue-300' : ''}`} onClick={() => setIsLayerMenuOpen(!isLayerMenuOpen)}>
              <Layers size={24} />
          </button>
          {isLayerMenuOpen && (
